package main

import (
	"crypto/rand"
	"encoding/base64"
	"fmt"
)

func generateSessionToken() string {
	token := make([]byte, 32)
	_, err := rand.Read(token)
	if err != nil {
		panic(err)
	}
	return base64.StdEncoding.EncodeToString(token)
}

func main() {
	fmt.Println(generateSessionToken())
}